struct Tag {
	Tag(): add(0) {}
	Tag(ll add): is_init(0), add(add) {}

	bool is_init = 1; // 初始化时不用 tag

	// 要维护的tag
	ll add;
	void apply(const Tag& t) {
		// 父tag怎么传到子tag
		if (not t.is_init) {
			is_init = 0;
			add += t.add;
		}
	}
};
