class ODT {
private:
	struct ODT_Node {
		ll l, r;
		mutable pll v; // { 颜色 c，刚变成颜色 c 时的 add[c] }

		// 重载小于号以用于 set 排序
		bool operator<(const ODT_Node& a)const {
			return l < a.l;
		}
	};

	// ODT 的核心操作：分裂区间
	// 将包含 pos 的区间 [l, r] 分裂为 [l, pos - 1] 和 [pos, r]
	// 返回指向后半段 [pos, r] 的迭代器
	auto split(int pos) {
		auto it = se.lower_bound({ pos, 0, {} });
		if (it != se.end() and it->l == pos)return it;

		it = prev(it);
		auto [l, r, v] = *it;
		se.erase(it);
		se.insert({ l, pos - 1, v });
		return se.insert({ pos, r, v }).first;
	}

public:

	set<ODT_Node> se;

	// ODT 的核心操作：区间赋值（推平）
	void assign(LazySegmentTree<Info, Tag>& t, const vector<ll>& add, int l, int r, int c) {
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;
			auto [c, last_add] = v;
			t.modifyRange(l, r, add[c] - last_add);
			it = se.erase(it); // 删除旧区间
		}

		// 插入新的白色区间
		se.insert({ l, r, { c, add[c] }});
	}

	pll query_last_add(int i) {
		auto it = split(i);
		return it->v;
	}
};

void solve(int CASE)
{
	ll n, q; cin >> n >> q;
	var add = vector<ll>(n + 1);
	var seg = LazySegmentTree<Info, Tag>(n + 1);
	var odt = ODT();
	odt.se.insert({ 1, n, {1, 0} });

	while (q--) {
		string op; cin >> op;
		if (op == "Color") {
			ll l, r, c; cin >> l >> r >> c;
			odt.assign(seg, add, l, r, c);
		}
		else if (op == "Add") {
			ll c, x; cin >> c >> x;
			add[c] += x;
		}
		else {
			ll i; cin >> i;
			var[c, last_add] = odt.query_last_add(i);
			ll ans = seg.query(i, i).val + add[c] - last_add;
			cout << ans << endl;
		}
	}
	return;
}
